mapper.select:
select count(x.guid) num, sum(x.total_price) total_price, sum(total_quantity) total_quantity, sum(net_weight) net_weight, sum(gross_weight) gross_weight, sum(v.shipmentnum) shipmentnum, sum(boxweight) boxweight, sum(boxnum) boxnum, sum(v.transweight) transweight from t_erp_ship_v2_inboundshipment_customs_xml x left join ( select p.shopid,p.groupid,p.marketplaceid,
i.ordguid guid,
i.invguid guid,
i.decguid guid,
i.decguid guid,
max(m.name) market, max(g.name) groupname, count(i.shipmentid) shipmentnum, -- 修正boxweight计算：先计算每个shipment的boxweight，再求和 sum( (select coalesce(sum(b.weight), 0) from t_erp_ship_v2_inboundshipment_box b where b.shipmentid = i.shipmentid) ) boxweight, -- 修正boxnum计算：统计每个shipment的box数量，再求和 sum( (select count(b.id) from t_erp_ship_v2_inboundshipment_box b where b.shipmentid = i.shipmentid) ) boxnum, sum(t.transweight) transweight from t_erp_ship_v2_inboundshipment i left join t_erp_ship_v2_inboundplan p on p.id = i.formid left join t_erp_ship_inboundtrans t on t.shipmentid = i.shipment_confirmation_id left join t_amazon_group g on g.id = p.groupid left join t_marketplace m on m.marketplaceid = p.marketplaceid where p.shopid=#{shopid}
and p.marketplaceid=#{marketplaceid}
and p.groupid=#{groupid}
group by p.shopid,p.groupid,p.marketplaceid,i.ordguid
group by p.shopid,p.groupid,p.marketplaceid,i.invguid
group by p.shopid,p.groupid,p.marketplaceid,i.decguid
group by p.shopid,p.groupid,p.marketplaceid,i.decguid
) v on v.guid=x.guid where v.shopid=#{shopid}
and x.groupid=#{groupid}
and x.xml_type=#{xmlType}
and v.marketplaceid=#{marketplaceid}
and x.app_time >=#{fromDate,jdbcType=DATE} and x.app_time <=#{toDate,jdbcType=DATE}
and x.opttime >=#{fromDate,jdbcType=DATE} and x.opttime <=#{toDate,jdbcType=DATE}

select x.*,v.market,v.groupname,v.shipmentnum,v.boxnum,v.boxweight,v.transweight from t_erp_ship_v2_inboundshipment_customs_xml x left join ( select p.shopid,p.groupid,p.marketplaceid,
i.ordguid guid,
i.invguid guid,
i.decguid guid,
i.decguid guid,
max(m.name) market, max(g.name) groupname, count(i.shipmentid) shipmentnum, -- 修正boxweight计算：先计算每个shipment的boxweight，再求和 sum( (select coalesce(sum(b.weight), 0) from t_erp_ship_v2_inboundshipment_box b where b.shipmentid = i.shipmentid) ) boxweight, -- 修正boxnum计算：统计每个shipment的box数量，再求和 sum( (select count(b.id) from t_erp_ship_v2_inboundshipment_box b where b.shipmentid = i.shipmentid) ) boxnum, sum(t.transweight) transweight from t_erp_ship_v2_inboundshipment i left join t_erp_ship_v2_inboundplan p on p.id = i.formid left join t_erp_ship_inboundtrans t on t.shipmentid = i.shipment_confirmation_id left join t_amazon_group g on g.id = p.groupid left join t_marketplace m on m.marketplaceid = p.marketplaceid where p.shopid=#{dto.shopid}
and p.marketplaceid=#{dto.marketplaceid}
and p.groupid=#{dto.groupid}
group by p.shopid,p.groupid,p.marketplaceid,i.ordguid
group by p.shopid,p.groupid,p.marketplaceid,i.invguid
group by p.shopid,p.groupid,p.marketplaceid,i.decguid
group by p.shopid,p.groupid,p.marketplaceid,i.decguid
) v on v.guid=x.guid where v.shopid=#{dto.shopid}
and x.groupid=#{dto.groupid}
and x.xml_type=#{dto.xmlType}
and v.marketplaceid=#{dto.marketplaceid}
and x.app_time >=#{dto.fromDate,jdbcType=DATE} and x.app_time <=#{dto.toDate,jdbcType=DATE}
and x.opttime >=#{dto.fromDate,jdbcType=DATE} and x.opttime <=#{dto.toDate,jdbcType=DATE}
